// Load 16 control bytes from offset g
__m128i group = _mm_loadu_si128(&metadata[g]);

cpp
// Compare all 16 bytes in 1 cycle
__m128i match = _mm_cmpeq_epi8(target, group);

cpp
// Convert vector to bitmask
uint32_t mask = _mm_movemask_epi8(match);
while (mask) {
int i = ctz(mask); // Find first match
verify_key(slots[g + i]);
